$ErrorActionPreference = 'Stop'
$repo = [Environment]::GetEnvironmentVariable('DCOIR_REPO_ROOT','Machine')
$downloads = [Environment]::GetEnvironmentVariable('DCOIR_DOWNLOADS_DIR','Machine')
if ([string]::IsNullOrWhiteSpace($repo)) { throw 'Missing DCOIR_REPO_ROOT' }
if ([string]::IsNullOrWhiteSpace($downloads)) { throw 'Missing DCOIR_DOWNLOADS_DIR' }
$script = Join-Path $repo 'operator_tools\github_desktop_lane\scripts\New-DcoirAirtableControlledVocabularyProfile.ps1'
$zipScript = Join-Path $repo 'operator_tools\github_desktop_lane\scripts\New-DcoirChatGPTFriendlyZip.ps1'
if (-not (Test-Path -LiteralPath $script -PathType Leaf)) { throw "Missing profile script: $script" }
if (-not (Test-Path -LiteralPath $zipScript -PathType Leaf)) { throw "Missing ZIP helper: $zipScript" }
$jsonText = & $script -OutputNamePrefix 'dcoir_wbs02_batch2_controlled_vocabulary_profile'
$resultPath = Join-Path $downloads 'dcoir_wbs02_batch2_controlled_vocabulary_profile_last_result.json'
$jsonText | Out-File -LiteralPath $resultPath -Encoding utf8
$result = $jsonText | ConvertFrom-Json
if ([string]$result.result -ne 'success') { throw ('Controlled vocabulary profile did not report success: ' + $jsonText) }
$outDir = [string]$result.output_dir
if ([string]::IsNullOrWhiteSpace($outDir) -or -not (Test-Path -LiteralPath $outDir -PathType Container)) { throw "Profile output folder missing: $outDir" }
$requestContext = [ordered]@{ request_id = 'exec-20260509-wbs02-batch2-cv-profile-001'; plan_key = 'PLAN-AIRTABLE-DB-REDESIGN-20260508'; wbs_scope = 'WBS02 Batch2 read-only controlled vocabulary profile'; mutation_planned = $false; include_delete_queue = $false; expected_next_payload = 'exact mapping approval packet after artifact review' }
$requestContext | ConvertTo-Json -Depth 10 | Out-File -LiteralPath (Join-Path $outDir 'request_context.json') -Encoding utf8
$zipPath = $outDir + '.chatgpt.zip'
& $zipScript -SourceFolder $outDir -OutputZip $zipPath -NormalizeTextEncoding
[ordered]@{ result='success'; request_id='exec-20260509-wbs02-batch2-cv-profile-001'; output_dir=$outDir; output_zip=$zipPath; result_path=$resultPath; mutation_planned=$false; include_delete_queue=$false } | ConvertTo-Json -Depth 10

